static void dump_topk_q15(const int16_t *p, int n, int k)
{
    if (!p || n <= 0 || k <= 0)
        return;

    // Simple O(n*k) selection (small n=64 typical).
    int idx[4] = {-1, -1, -1, -1};
    int16_t val[4] = {-(int16_t)32768, -(int16_t)32768, -(int16_t)32768, -(int16_t)32768};
    if (k > 4)
        k = 4;

    for (int i = 0; i < n; ++i)
    {
        int16_t v = p[i];
        for (int j = 0; j < k; ++j)
        {
            if (v > val[j])
            {
                // shift down
                for (int t = k - 1; t > j; --t)
                {
                    val[t] = val[t - 1];
                    idx[t] = idx[t - 1];
                }
                val[j] = v;
                idx[j] = i;
                break;
            }
        }
    }

    for (int j = 0; j < k; ++j)
    {
        printf("  #%d: t=%d q15=%d\n", j, idx[j], (int)val[j]);
    }
}

static void dump_i8_prefix(const char *name, const int8_t *x, int n, int max_print)
{
    if (!x || n <= 0)
        return;
    if (max_print > n)
        max_print = n;
    printf("[TT] %s (int8) prefix[%d]: ", name ? name : "vec", max_print);
    for (int i = 0; i < max_print; ++i)
        printf("%d%s", (int)x[i], (i == max_print - 1) ? "\n" : ",");
}

static void dump_topk_i32(const int32_t *x, int n, int k)
{
    if (!x || n <= 0 || k <= 0)
        return;
    if (k > 4)
        k = 4;
    int idx[4] = {-1, -1, -1, -1};
    int32_t val[4] = {INT32_MIN, INT32_MIN, INT32_MIN, INT32_MIN};
    for (int i = 0; i < n; ++i)
    {
        int32_t v = x[i];
        for (int j = 0; j < k; ++j)
        {
            if (v > val[j])
            {
                for (int t = k - 1; t > j; --t)
                {
                    val[t] = val[t - 1];
                    idx[t] = idx[t - 1];
                }
                val[j] = v;
                idx[j] = i;
                break;
            }
        }
    }
    for (int j = 0; j < k; ++j)
        printf("  #%d: t=%d val=%ld\n", j, idx[j], (long)val[j]);
}

void prof_hw_init(void)
{
    // Inizializza il timer per contare i clock
    timer_cycles_init();
    // Avvia il timer in modalità free-running
    timer_start();
}

uint64_t prof_now(void)
{
    // Legge il valore corrente del timer HW.
    return (uint64_t)timer_get_cycles();
}

// ---------------------------
// Compile-time configuration
// ---------------------------
// Fixed sequence length for the test (must match your kernels' assumptions)
#define T 64
// Classifier output tiling for streamed FC
#define OC_BLK 32

// Derive constants at compile-time (no VLAs)
enum
{
    C_IN = MODEL_IN_CHANNELS,
    C = MODEL_D_MODEL,
    TOKENS = T,
    WIN_LEN = (MODEL_ATTENTION_WINDOW <= 0 || MODEL_ATTENTION_WINDOW >= TOKENS)
                     ? TOKENS
                     : (2 * MODEL_ATTENTION_WINDOW + 1),
    // Hidden size = OUT of block0 MLP.FC1 (6-per-block layout: index 4 = blk0.mlp.fc1)
    H = FC4_OUT
};

// -------- Determine the maximum hidden size across blocks (for shared FC tiles) --------
// fc index layout (from exporter, 6 per block — split Q/K/V):
//   6*i+0: blk{i}.mha.q,    6*i+1: blk{i}.mha.k,    6*i+2: blk{i}.mha.v,
//   6*i+3: blk{i}.mha.proj, 6*i+4: blk{i}.mlp.fc1,  6*i+5: blk{i}.mlp.fc2
//   then: attnpool.fc0, attnpool.fc1, classifier
// mlp.fc1 is at index 6*i+4: depth=1 -> FC4_OUT, depth=2 -> FC4/FC10, etc.
#if MODEL_DEPTH == 1
#define H_MAX (FC4_OUT)
#elif MODEL_DEPTH == 2
#define H_MAX ((FC4_OUT > FC10_OUT) ? FC4_OUT : FC10_OUT)
#elif MODEL_DEPTH == 3
#define H_MAX (((FC4_OUT > FC10_OUT) ? FC4_OUT : FC10_OUT) > FC16_OUT \
                      ? ((FC4_OUT > FC10_OUT) ? FC4_OUT : FC10_OUT)      \
                      : FC16_OUT)
#elif MODEL_DEPTH == 4
#define H_MAX (((FC4_OUT > FC10_OUT) ? FC4_OUT : FC10_OUT) > \
               ((FC16_OUT > FC22_OUT) ? FC16_OUT : FC22_OUT) \
                      ? ((FC4_OUT > FC10_OUT) ? FC4_OUT : FC10_OUT) \
                      : ((FC16_OUT > FC22_OUT) ? FC16_OUT : FC22_OUT))
#else
#define H_MAX (FC4_OUT) /* extend similarly if you build deeper */
#endif
#define WMAX ((H_MAX > C) ? H_MAX : C)

// Basic sanity (compile-time where possible)
#if (MODEL_D_MODEL % MODEL_NHEAD) != 0
#error "d_model must be divisible by nhead"
#endif

