        return;
    case ERR_RD_LN_BLK3_MLP_GAMMA:
        printf("[TT] FLASH read failed: LN blk3 MLP gamma\n");
        return;
    case ERR_RD_LN_BLK3_MLP_BETA:
        printf("[TT] FLASH read failed: LN blk3 MLP beta\n");
        return;
    case ERR_RD_LN_FINAL_GAMMA:
        printf("[TT] FLASH read failed: LN final gamma\n");
        return;
    case ERR_RD_LN_FINAL_BETA:
        printf("[TT] FLASH read failed: LN final beta\n");
        return;
    case ERR_RD_LN_AP_GAMMA:
        printf("[TT] FLASH read failed: LN attnpool gamma\n");
        return;
    case ERR_RD_LN_AP_BETA:
        printf("[TT] FLASH read failed: LN attnpool beta\n");
        return;
    case ERR_RD_LN_CLS_GAMMA:
        printf("[TT] FLASH read failed: LN classifier gamma\n");
        return;
    case ERR_RD_LN_CLS_BETA:
        printf("[TT] FLASH read failed: LN classifier beta\n");
        return;

    case ERR_RD_ACT_SCALES:
        printf("[TT] FLASH read failed: activation scales (Q31)\n");
        return;

    // AttnPool streamed mapping
    case ERR_AP_BAD_ARGS:
        printf("[TT][AttnPool] bad args / geometry\n");
        return;
    case ERR_AP_RD_FC0_B:
        printf("[TT][AttnPool] FLASH read failed: FC0 bias tile\n");
        return;
